from haystack import component
from subprocess import run, PIPE
import docker

@component
class SandboxExecutor:
    @component.output_types(execution_result=str, success=bool)
    def run_code(self, code: str) -> dict:
        client = docker.from_env()
        container = client.containers.run(
            "python:3.11-slim",
            command=f"python -c '{code}'",
            mem_limit="256m",
            cpu_quota=100000,
            detach=False,
            remove=True
        )
        return {"execution_result": container.decode('utf-8'), "success": True}

import tempfile
import pytest
from haystack import component

@component
class TestValidator:
    @component.output_types(passed=bool, failures=list)
    def validate_code(self, code: str, expected_output: str) -> dict:
        with tempfile.TemporaryDirectory() as tmpdir:
            test_file = f"{tmpdir}/test_code.py"
            with open(test_file, 'w') as f:
                f.write(f"""
def test_generated_code():
    exec({{{code!r}}})
    assert 'expected_result' in locals()
""")
            result = pytest.main([test_file, '-v'])
        return {"passed": result == 0, "failures": []}

