from vex_sdk import VexClient
from haystack import component

@component
class VexGuardrailNode:
    def __init__(self):
        self.vex = VexClient(api_key="your-vex-key")

    @component.input_types(code=str)
    @component.output_types(safe=bool, issues=list)
    def verify_code(self, code: str) -> dict:
        results = self.vex.verify(
            content=code,
            verifications=[
                "code_safety",
                "syntax_validity",
                "no_credential_leakage",
                "dependency_safety"
            ]
        )
        return {
            "safe": results.passed,
            "issues": results.issues
        }

def monitor_refinement_loop(pipeline, max_iterations=5):
    results = []
    for i in range(max_iterations):
        result = pipeline.run({
            "generator": {"prompt": f"Iteration {i+1}: {{query}}"}
        })

        vex_result = VexClient().verify(
            content=result["vex_guardrail.issues"],
            verifications=["execution_sandboxing"]
        )

        if not vex_result.passed:
            print(f"Iteration {i+1} blocked: {vex_result.issues}")
            break
        results.append(result)
    return results
